const panelId     = $('Config').first().json.PANEL_SPREADSHEET_ID;
const clienteNombre = $('Config').first().json.CLIENTE_NOMBRE;

const rows = $input.all().map(i => i.json);
const row  = rows.find(r => (r.CLIENTE_NOMBRE || '').toLowerCase().trim() === clienteNombre.toLowerCase().trim());
if (!row) throw new Error(`Cliente "${clienteNombre}" no encontrado en el Panel sheet`);

const mes  = parseInt(row.mes_actual);
const anio = parseInt(row.anio_actual);
const comparacion = (row.comparacion || 'mes anterior').toLowerCase();

const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];

// Período actual
const lastDay = new Date(anio, mes, 0).getDate();
const fechaInicioActual  = `${anio}-${String(mes).padStart(2,'0')}-01`;
const fechaFinActual     = `${anio}-${String(mes).padStart(2,'0')}-${lastDay}`;
const periodoActualLabel = `${meses[mes-1]} ${anio}`;

// Período anterior según comparacion
let mP, aP;
if (comparacion.includes('año')) {
  mP = mes; aP = anio - 1;
} else {
  mP = mes === 1 ? 12 : mes - 1;
  aP = mes === 1 ? anio - 1 : anio;
}
const lastDayP = new Date(aP, mP, 0).getDate();
const fechaInicioAnterior  = `${aP}-${String(mP).padStart(2,'0')}-01`;
const fechaFinAnterior     = `${aP}-${String(mP).padStart(2,'0')}-${lastDayP}`;
const periodoAnteriorLabel = `${meses[mP-1]} ${aP}`;

return [{ json: {
  PANEL_SPREADSHEET_ID:  panelId,
  CLIENTE_NOMBRE:        row.CLIENTE_NOMBRE,
  CLIENTE_LOGO_URL:      row.CLIENTE_LOGO_URL || '',
  Plataforma:            row.Plataforma || 'WOOWUP',
  dashbo_client_id:      String(row.dashbo_client_id || ''),
  SPREADSHEET_ID_ACTUAL:   row.SPREADSHEET_ID_ACTUAL,
  SPREADSHEET_ID_ANTERIOR: row.SPREADSHEET_ID_ANTERIOR,
  CUSTOM_TAB:            row['Custom Tab'] || '',
  PERIODO_ACTUAL_LABEL:  periodoActualLabel,
  PERIODO_ANTERIOR_LABEL: periodoAnteriorLabel,
  FECHA_INICIO_ACTUAL:   fechaInicioActual,
  FECHA_FIN_ACTUAL:      fechaFinActual,
  FECHA_INICIO_ANTERIOR: fechaInicioAnterior,
  FECHA_FIN_ANTERIOR:    fechaFinAnterior,
}}];

